import{_ as a,o as s,c as r,a2 as o}from"./chunks/framework.D5wUhsuj.js";const t="/docs/assets/users-page.2KHaKJoq.png",n="/docs/assets/create-user-dialog.DqoP5-9y.png",i="/docs/assets/workspaces-page.CsEyoHMX.png",c="/docs/assets/create-workspace-dialog.DqPwb_kL.png",l="/docs/assets/workspace-members-panel.D_bD1hP8.png",p="/docs/assets/workspace-security-policy-dialog.C-g3PkC_.png",d="/docs/assets/workspace-egress-profile-dialog.CVngINYj.png",g="/docs/assets/groups-page.CIKuDT00.png",m="/docs/assets/create-group-dialog.DmOAPag4.png",u="/docs/assets/group-management-panel.BEQjAGQJ.png",P=JSON.parse('{"title":"User Management","description":"","frontmatter":{},"headers":[],"relativePath":"admin/user_management.md","filePath":"admin/user_management.md","lastUpdated":1783462857000}'),h={name:"admin/user_management.md"};function k(w,e,f,b,y,_){return s(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="user-management" tabindex="-1">User Management <a class="header-anchor" href="#user-management" aria-label="Permalink to &quot;User Management&quot;">​</a></h1><p>Administrators can manage users, workspaces, groups, and workspace access from the prokube UI. Use the UI for day-to-day administration instead of editing identity-provider roles directly.</p><h2 id="user-management-area" tabindex="-1">User Management Area <a class="header-anchor" href="#user-management-area" aria-label="Permalink to &quot;User Management Area&quot;">​</a></h2><p>Open <strong>User Management</strong> in the admin area. It provides pages for:</p><ul><li><strong>Users</strong>: create, search, edit, disable, and delete users;</li><li><strong>Workspaces</strong>: create and delete workspaces, manage workspace members, enforce workspace security policy settings, and assign egress profiles;</li><li><strong>Groups</strong>: create and delete groups, manage group members, and grant or revoke group access to workspaces;</li><li><strong>Network Policies</strong>: define reusable egress profiles for workspace outbound access.</li></ul><p>The underlying identity provider remains Keycloak. Use the Keycloak admin console only for advanced IAM tasks that are not exposed in the prokube UI.</p><p>Common platform roles are:</p><ul><li><code>pk-user</code>: allows normal platform access for authenticated users;</li><li><code>pk-admin</code>: grants access to administrator views and platform administration workflows;</li><li><code>pk:&lt;workspace-name&gt;</code>: grants access to a specific workspace namespace.</li></ul><p>Prefer assigning workspace access through the prokube UI. Direct role edits in Keycloak are easy to misapply and can affect Kubernetes, object-storage, and workload access.</p><h2 id="users" tabindex="-1">Users <a class="header-anchor" href="#users" aria-label="Permalink to &quot;Users&quot;">​</a></h2><p>Open <strong>User Management</strong> &gt; <strong>Users</strong> to view platform users. The table shows username, email address, group memberships, account status, and creation time. Use search to find users by username or email.</p><p><img src="'+t+'" alt="Users page" loading="lazy"></p><p>To create a user:</p><ol><li>Click <strong>Create User</strong>.</li><li>Enter username, email, first name, last name, and an initial password.</li><li>Keep <strong>Require password change</strong> enabled unless you have a specific reason not to.</li><li>Save the user.</li></ol><p><img src="'+n+'" alt="Create User dialog" loading="lazy"></p><p>To update a user, open the row action menu and choose <strong>Edit</strong>. The prokube UI can update the user&#39;s first name, last name, and enabled status. Usernames and email addresses are not changed from this dialog.</p><p>To delete a user, open the row action menu and choose <strong>Delete</strong>. Deleting a user removes the account and revokes platform access.</p><h2 id="workspaces" tabindex="-1">Workspaces <a class="header-anchor" href="#workspaces" aria-label="Permalink to &quot;Workspaces&quot;">​</a></h2><p>Open <strong>User Management</strong> &gt; <strong>Workspaces</strong> to manage workspace namespaces. The table shows each workspace name, workspace type, member count, group access, security policy state, egress profile assignment, and available actions.</p><p><img src="'+i+'" alt="Workspaces page" loading="lazy"></p><p>To create a workspace:</p><ol><li>Click <strong>Create Workspace</strong>.</li><li>Enter a Kubernetes-compatible workspace name.</li><li>Select an owner user.</li><li>Save the workspace.</li></ol><p>Workspace names must be Kubernetes-compatible DNS labels: lowercase letters, numbers, and hyphens, starting and ending with a letter or number.</p><p>The platform creates the required cluster resources. The workspace owner is shown separately from regular members in the member management panel.</p><p><img src="'+c+'" alt="Create Workspace dialog" loading="lazy"></p><p>To manage workspace members, click <strong>Manage</strong> on a workspace row. Use the side panel to add users, search existing members, or remove members. Added members receive editor access to the workspace.</p><p><img src="'+l+'" alt="Workspace members panel" loading="lazy"></p><p>Personal workspaces are tied to user lifecycle and cannot be deleted from the Workspaces page while attached to a user.</p><h3 id="workspace-security-policy" tabindex="-1">Workspace Security Policy <a class="header-anchor" href="#workspace-security-policy" aria-label="Permalink to &quot;Workspace Security Policy&quot;">​</a></h3><p>Use the shield action in the workspace row to enforce or remove the workspace security policy.</p><p>When enforced, prokube sets the <code>prokube.ai/security-policy: enforced</code> annotation, applies restricted pod security labels, and requires new and updated Labs in that workspace to use hardened security settings.</p><p>Review workloads in the workspace before enforcing the policy. Existing workloads or custom images may need changes if they rely on privileged behavior.</p><p><img src="'+p+'" alt="Workspace security policy dialog" loading="lazy"></p><h3 id="workspace-egress-profile" tabindex="-1">Workspace Egress Profile <a class="header-anchor" href="#workspace-egress-profile" aria-label="Permalink to &quot;Workspace Egress Profile&quot;">​</a></h3><p>Use <strong>Assign Egress Profile</strong> from the workspace row actions to attach or clear an egress profile. The Workspaces table shows the current assignment and a short destination summary.</p><p>Each workspace can have one egress profile assignment. Egress profiles are created under <strong>User Management</strong> &gt; <strong>Network Policies</strong> and define the external host, protocol, and port combinations workloads are allowed to reach.</p><p>See <a href="./network_policies.html">Network Policies</a> for profile creation, destination rules, and operational notes.</p><p><img src="'+d+'" alt="Workspace egress profile dialog" loading="lazy"></p><h3 id="delete-a-workspace" tabindex="-1">Delete a Workspace <a class="header-anchor" href="#delete-a-workspace" aria-label="Permalink to &quot;Delete a Workspace&quot;">​</a></h3><p>Deleting a workspace is destructive and cannot be undone. The UI requires typing the workspace name to confirm.</p><p>Workspace deletion removes the namespace and Kubernetes resources in it, including Labs, volumes, secrets, configurations, deployed models, services, pipelines, experiments, and pipeline runs. Object-storage data may be archived rather than deleted, depending on the platform configuration.</p><p>Before deleting a workspace, confirm that required data has been exported or archived according to your organization&#39;s retention policy.</p><h2 id="groups" tabindex="-1">Groups <a class="header-anchor" href="#groups" aria-label="Permalink to &quot;Groups&quot;">​</a></h2><p>Open <strong>User Management</strong> &gt; <strong>Groups</strong> to manage groups. Groups are useful when multiple users need the same workspace access.</p><p><img src="'+g+'" alt="Groups page" loading="lazy"></p><p>The Groups page supports search and pagination. The management panel shows group members and workspace access for the selected group.</p><p>To create a group:</p><ol><li>Click <strong>Create Group</strong>.</li><li>Enter the group name and optional description.</li><li>Save the group.</li></ol><p><img src="'+m+'" alt="Create Group dialog" loading="lazy"></p><p>To manage a group, click <strong>Manage</strong> on the group row. The side panel lets you add or remove members and grant or revoke workspace access.</p><p><img src="'+u+'" alt="Group management panel" loading="lazy"></p><p>Granting workspace access adds the corresponding <code>pk:&lt;workspace-name&gt;</code> role to the group. All group members receive access to that workspace.</p><p>The Workspaces page also shows which groups have access to each workspace. Use groups for team access instead of adding many users individually.</p><p>To delete a group, use the row action menu. Deleting a group removes the group membership relationship, but it does not delete users or workspaces.</p><h2 id="advanced-iam-in-keycloak" tabindex="-1">Advanced IAM in Keycloak <a class="header-anchor" href="#advanced-iam-in-keycloak" aria-label="Permalink to &quot;Advanced IAM in Keycloak&quot;">​</a></h2><p>Keycloak remains the identity provider behind prokube. Use the Keycloak admin console for advanced IAM operations that are not exposed in the prokube UI, such as:</p><ul><li>external identity provider setup;</li><li>authentication flow changes;</li><li>advanced role mapping;</li><li>email configuration;</li><li>credential reset emails;</li><li>low-level realm or client configuration.</li></ul><p>Identity administration is security-sensitive. Access admin consoles only over trusted TLS and with administrator accounts protected by your organization&#39;s required controls.</p><p>Prefer creating and deleting workspaces through the prokube UI. If you must manage workspace roles directly in Keycloak, workspace roles use the <code>pk:&lt;workspace-name&gt;</code> naming pattern. Direct role changes can affect workspace access and should be made carefully.</p><h2 id="security-notes" tabindex="-1">Security Notes <a class="header-anchor" href="#security-notes" aria-label="Permalink to &quot;Security Notes&quot;">​</a></h2><ul><li>Grant users and groups the minimum workspace access they need.</li><li>Prefer group-based access for teams instead of one-off user role assignments.</li><li>Treat shared workspace secrets as visible to users with sufficient workspace permissions.</li><li>Use service accounts or workload-specific credentials for shared automation instead of personal credentials.</li><li>Review workspace contents before deleting users or workspaces; Kubernetes resources may be deleted permanently while object-storage data may follow a separate archive policy.</li></ul><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../platform/workspaces.html">Workspaces</a></li><li><a href="./network_policies.html">Network Policies</a></li><li><a href="./../platform/kubernetes.html">Kubernetes Resources</a></li><li><a href="./../platform/api_keys.html">API Keys</a></li><li><a href="./">Admin Documentation</a></li></ul>',63)])])}const U=a(h,[["render",k]]);export{P as __pageData,U as default};
